create type public.redemption_kind as enum('benefit','credit');create type public.redemption_status as enum('submitted','approved','rejected','cancelled','fulfilled');
create table public.redemption_requests(id uuid primary key default gen_random_uuid(),account_id uuid not null references public.reward_accounts(id),submitted_by uuid not null references public.profiles(id),kind public.redemption_kind not null,benefit_id text references public.benefit_definitions(id),reward_type text,quantity numeric(12,2) not null check(quantity>0),usage_year int not null default extract(year from now()),customer_notes text not null default'',order_reference text,status public.redemption_status not null default'submitted',staff_notes text,reviewed_by uuid references public.profiles(id),reviewed_at timestamptz,fulfilled_at timestamptz,benefit_usage_id uuid references public.benefit_usage(id),reward_ledger_id uuid references public.reward_ledger(id),idempotency_key uuid not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(submitted_by,idempotency_key),check((kind='benefit'and benefit_id is not null and reward_type is null)or(kind='credit'and benefit_id is null and reward_type is not null)));
create trigger redemption_set_updated_at before update on public.redemption_requests for each row execute function public.set_updated_at();alter table public.redemption_requests enable row level security;create policy redemption_read on public.redemption_requests for select to authenticated using(public.can_access_account(account_id)or public.is_staff());grant select on public.redemption_requests to authenticated;revoke all on public.redemption_requests from anon;
create or replace function public.submit_benefit_redemption(p_account_id uuid,p_benefit_id text,p_quantity numeric,p_notes text,p_idempotency_key uuid)returns uuid language plpgsql security definer set search_path=public as $$declare r uuid;allowance numeric;used numeric;reserved numeric;tier text;begin if not public.can_access_account(p_account_id)then raise exception'Account access denied';end if;perform pg_advisory_xact_lock(hashtext(p_account_id::text));select tier_id into tier from public.account_current_tiers where account_id=p_account_id;select annual_allowance into allowance from public.benefit_definitions where id=p_benefit_id and active and tier_id=tier;if not found then raise exception'Benefit is not available for this tier';end if;if allowance is not null then select coalesce(sum(quantity),0)into used from public.benefit_usage where account_id=p_account_id and benefit_id=p_benefit_id and usage_year=extract(year from now());select coalesce(sum(quantity),0)into reserved from public.redemption_requests where account_id=p_account_id and benefit_id=p_benefit_id and usage_year=extract(year from now())and status in('submitted','approved');if p_quantity>allowance-used-reserved then raise exception'Request exceeds available benefit balance';end if;insert into public.redemption_requests(account_id,submitted_by,kind,benefit_id,quantity,customer_notes,idempotency_key)values(p_account_id,auth.uid(),'benefit',p_benefit_id,p_quantity,coalesce(p_notes,''),p_idempotency_key)returning id into r;insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id,details)values(auth.uid(),'redemption_submitted','redemption_request',r::text,jsonb_build_object('kind','benefit'));return r;end$$;
create or replace function public.submit_credit_redemption(p_account_id uuid,p_amount numeric,p_notes text,p_order_reference text,p_idempotency_key uuid)returns uuid language plpgsql security definer set search_path=public as $$declare r uuid;balance numeric;reserved numeric;begin if not public.can_access_account(p_account_id)then raise exception'Account access denied';end if;perform pg_advisory_xact_lock(hashtext(p_account_id::text));select coalesce(sum(amount),0)into balance from public.reward_ledger where account_id=p_account_id and(expires_at is null or expires_at>now());select coalesce(sum(quantity),0)into reserved from public.redemption_requests where account_id=p_account_id and kind='credit'and status in('submitted','approved');if p_amount>balance-reserved then raise exception'Request exceeds available credit';end if;insert into public.redemption_requests(account_id,submitted_by,kind,reward_type,quantity,customer_notes,order_reference,idempotency_key)values(p_account_id,auth.uid(),'credit','reward_credit_usd',p_amount,coalesce(p_notes,''),p_order_reference,p_idempotency_key)returning id into r;insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id,details)values(auth.uid(),'redemption_submitted','redemption_request',r::text,jsonb_build_object('kind','credit'));return r;end$$;
create or replace function public.cancel_redemption_request(p_id uuid)returns void language plpgsql security definer set search_path=public as $$begin update public.redemption_requests set status='cancelled'where id=p_id and submitted_by=auth.uid()and status='submitted';if not found then raise exception'Request cannot be cancelled';end if;end$$;
create or replace function public.review_redemption_request(p_id uuid,p_status public.redemption_status,p_notes text)returns void language plpgsql security definer set search_path=public as $$begin if not public.is_staff()then raise exception'Staff access required';end if;if p_status not in('approved','rejected')then raise exception'Invalid review status';end if;update public.redemption_requests set status=p_status,staff_notes=p_notes,reviewed_by=auth.uid(),reviewed_at=now()where id=p_id and status='submitted';if not found then raise exception'Request is not awaiting review';end if;end$$;
create or replace function public.fulfill_redemption_request(p_id uuid,p_notes text default null)returns void language plpgsql security definer set search_path=public as $$declare r public.redemption_requests%rowtype;entry uuid:=gen_random_uuid();begin if not public.is_staff()then raise exception'Staff access required';end if;select*into r from public.redemption_requests where id=p_id for update;if r.status<>'approved'then raise exception'Request is not approved';end if;perform pg_advisory_xact_lock(hashtext(r.account_id::text));if r.kind='benefit'then insert into public.benefit_usage(id,account_id,benefit_id,quantity,usage_year,description,recorded_by)values(entry,r.account_id,r.benefit_id,r.quantity,r.usage_year,coalesce(p_notes,r.customer_notes,'Benefit redemption'),auth.uid());update public.redemption_requests set status='fulfilled',fulfilled_at=now(),benefit_usage_id=entry,staff_notes=coalesce(p_notes,staff_notes)where id=p_id;else insert into public.reward_ledger(id,account_id,reward_type,amount,description,created_by)values(entry,r.account_id,r.reward_type,-r.quantity,coalesce(p_notes,r.customer_notes,'Credit redemption'),auth.uid());update public.redemption_requests set status='fulfilled',fulfilled_at=now(),reward_ledger_id=entry,staff_notes=coalesce(p_notes,staff_notes)where id=p_id;end if;insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id,details)values(auth.uid(),'redemption_fulfilled','redemption_request',p_id::text,jsonb_build_object('kind',r.kind,'quantity',r.quantity));end$$;
revoke execute on function public.submit_benefit_redemption(uuid,text,numeric,text,uuid),public.submit_credit_redemption(uuid,numeric,text,text,uuid),public.cancel_redemption_request(uuid),public.review_redemption_request(uuid,public.redemption_status,text),public.fulfill_redemption_request(uuid,text)from public,anon;grant execute on function public.submit_benefit_redemption(uuid,text,numeric,text,uuid),public.submit_credit_redemption(uuid,numeric,text,text,uuid),public.cancel_redemption_request(uuid),public.review_redemption_request(uuid,public.redemption_status,text),public.fulfill_redemption_request(uuid,text)to authenticated;
